**AFTER (Redis Sorted Set 기반 대기열 + Spring Cache 차단 목록)**

파일 위치: `api/src/main/kotlin/com/maum/backend/service/call/CallMatchCacheService.kt`

```kotlin
@Service
class CallMatchCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val blockRepository: BlockRepository,
) {
    companion object {
        // 대기열: gender별로 분리 (남성 대기열 / 여성 대기열)
        private const val MATCH_QUEUE_KEY = "call:match:queue:"     // + gender
        private const val BLOCK_LIST_KEY  = "call:block:"           // + userId
        private const val MATCH_QUEUE_TTL = 10L                     // 10분 (대기 타임아웃)
        private const val BLOCK_LIST_TTL  = 30L                     // 30분
    }

    // 대기열 등록: Sorted Set score = 등록 시각(epoch milli)
    fun enqueueUser(userId: String, gender: String) {
        val key = "$MATCH_QUEUE_KEY$gender"
        val score = System.currentTimeMillis().toDouble()
        redisTemplate.opsForZSet().add(key, userId, score)
        redisTemplate.expire(key, Duration.ofMinutes(MATCH_QUEUE_TTL))
    }

    // 반대 성별 대기열에서 가장 오래 기다린 후보 N명 조회
    fun pollCandidates(excludeGender: String, count: Long = 20): Set<String> {
        val key = "$MATCH_QUEUE_KEY$excludeGender"
        return redisTemplate.opsForZSet()
            .range(key, 0, count - 1) ?: emptySet()
    }

    // 차단 목록 캐싱 (30분 TTL)
    @Cacheable(cacheNames = ["blockList"], key = "#userId", unless = "#result.isEmpty()")
    fun getBlockedUserIds(userId: String): Set<String> {
        return blockRepository.findBlockedIdsByUserId(userId).toSet()
    }

    // 매칭 완료 시 양쪽 대기열에서 제거
    fun dequeueUsers(userId1: String, gender1: String, userId2: String, gender2: String) {
        redisTemplate.opsForZSet().remove("$MATCH_QUEUE_KEY$gender1", userId1)
        redisTemplate.opsForZSet().remove("$MATCH_QUEUE_KEY$gender2", userId2)
    }

    // 차단 목록 무효화 (차단/차단해제 이벤트 발생 시)
    @CacheEvict(cacheNames = ["blockList"], key = "#userId")
    fun evictBlockList(userId: String) {}
}
```

